#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    vector<int> a(10), b(10);
    for (int i = 0; i < 10; i++) cin >> a[i];
    for (int i = 0; i < 10; i++) cin >> b[i];

    // All possible amounts in barn1's tank on Friday evening
    // Start: 1000
    // Tue: barn1 loses some bucket amount x (from a), barn2 gains x
    // Wed: barn2 loses some bucket amount y (from the set of 10 buckets currently in barn2 = b + {x} after Tue), barn1 gains y
    // Thu: barn1 loses some bucket amount z (from the set of 10 buckets currently in barn1 = a - {x} + {y}), barn2 gains z
    // Fri: barn2 loses some bucket amount w (from the set of 10 buckets currently in barn2 = b + {x} - {y} + {z}), barn1 gains w
    //
    // Net change to barn1 = -x + y - z + w
    // So final amount = 1000 + (-x + y - z + w)

    // But x is chosen from a (original barn1 buckets)
    // y is chosen from (b union {x})
    // z is chosen from (a - {x} union {y})
    // w is chosen from (b union {x} - {y} union {z})

    // Brute force all possibilities: x from a, y from b or x, z from a or y (but can't be x if x still there? careful)
    // The bucket is moved and left in the destination barn. So each time the set of buckets in a barn is:
    // Initially: barn1 has A = multiset a, barn2 has B = multiset b
    // After Tue: barn1 has A without one copy of x, barn2 has B with one extra copy of x
    // After Wed: barn2 has (B + {x}) without one copy of y, barn1 has (A - {x}) with one extra copy of y
    // After Thu: barn1 has (A - {x} + {y}) without one copy of z, barn2 has (B + {x} - {y}) with one extra copy of z
    // After Fri: barn2 has (B + {x} - {y} + {z}) without one copy of w, barn1 has (A - {x} + {y} - {z}) with one extra copy of w
    //
    // Net barn1 = 1000 - x + y - z + w

    // Since bucket capacities are small (1..100) and only 10 per barn, we can brute force all combinations.
    // Max possibilities: 10 * (11) * (up to 11) * (up to 11) ≈ 10*11*11*11 = 13310, trivial.

    set<int> results;

    for (int xi = 0; xi < 10; xi++) {
        int x = a[xi];

        // Multiset for barn2 after Tue: b + {x}
        vector<int> b2 = b;
        b2.push_back(x); // size 11

        for (int yi = 0; yi < (int)b2.size(); yi++) {
            int y = b2[yi];

            // Multiset for barn1 after Wed: (a - {x}) + {y}
            vector<int> a1;
            bool used_x = false;
            for (int i = 0; i < 10; i++) {
                if (!used_x && a[i] == x) {
                    used_x = true;
                    continue;
                }
                a1.push_back(a[i]);
            }
            a1.push_back(y); // size 10

            for (int zi = 0; zi < (int)a1.size(); zi++) {
                int z = a1[zi];

                // Multiset for barn2 after Thu: (b2 - {y}) + {z}
                vector<int> b3;
                bool used_y = false;
                for (int i = 0; i < (int)b2.size(); i++) {
                    if (!used_y && b2[i] == y) {
                        used_y = true;
                        continue;
                    }
                    b3.push_back(b2[i]);
                }
                b3.push_back(z); // size 11 again

                for (int wi = 0; wi < (int)b3.size(); wi++) {
                    int w = b3[wi];
                    int amount = 1000 - x + y - z + w;
                    results.insert(amount);
                }
            }
        }
    }

    cout << results.size() << "\n";

    return 0;
}
